import{_ as s,o as e,c as a,a6 as i,au as o,av as n,aw as r,ax as l,ay as p}from"./chunks/framework.UYVGz2W_.js";const y=JSON.parse('{"title":"Bots","description":"","frontmatter":{},"headers":[],"relativePath":"bots/index.md","filePath":"bots/index.md"}'),h={name:"bots/index.md"};function c(u,t,g,d,k,m){return e(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="bots" tabindex="-1">Bots <a class="header-anchor" href="#bots" aria-label="Permalink to “Bots”">​</a></h1><p>Bots in Kitsu are non-physical users that can perform automated tasks, allowing you to run scripts and interact with Kitsu&#39;s API without logging in as a real user.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Bots do not count as active users, so you can create as many as you need, regardless of your subscription plan.</p></div><h2 id="why-use-a-bot" tabindex="-1">Why Use a Bot <a class="header-anchor" href="#why-use-a-bot" aria-label="Permalink to “Why Use a Bot”">​</a></h2><p>The primary use of bots is for scripting with Gazu or other applications that can use the Kitsu API. Bots can access almost all API routes except those limited to real users.</p><p><strong>Key Benefits:</strong></p><ul><li>Perform automated tasks and scripts</li><li>Interact with Kitsu&#39;s API</li><li>Maintain system security by using tokens</li></ul><h2 id="how-to-create-a-bot" tabindex="-1">How to Create a Bot <a class="header-anchor" href="#how-to-create-a-bot" aria-label="Permalink to “How to Create a Bot”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>When you first create a bot, you will receive a <strong>JWT token</strong>. This token is crucial for connecting to the API, so make sure to keep it safe.</p></div><ol><li><p><strong>Navigate to the Bots Page:</strong> On the Main Menu, under the Admin section, go to the Bots page.</p><p><img src="'+o+'" alt="Main menu Bots"></p></li><li><p><strong>Add a New Bot:</strong> Click on the <img src="'+n+'" alt="New Bots"> button. A pop-up window will appear where you can fill in the bot&#39;s details.</p><ul><li><strong>Name:</strong> Give your bot a name.</li><li><strong>Expiration Date:</strong> Set an expiration date if needed.</li><li><strong>Departments:</strong> Link the bot to a specific department.</li><li><strong>Role:</strong> Define the role of the bot.</li><li><strong>Active:</strong> Choose whether the bot is active or inactive.</li></ul><p><img src="'+r+'" alt="Main creation Bots"></p></li><li><p><strong>Create the Bot:</strong> Fill in the details and click <strong>Create user</strong>.</p><p><img src="'+l+'" alt="Example creation Bots"></p></li></ol><p>A new pop-up will display the bot&#39;s <strong>API token</strong>.</p><p><img src="'+p+`" alt="Example Bots Token"></p><h2 id="managing-bots" tabindex="-1">Managing Bots <a class="header-anchor" href="#managing-bots" aria-label="Permalink to “Managing Bots”">​</a></h2><p>On the Bots page, you can manage your bots just like any user, such as:</p><ul><li>Assigning a role</li><li>Setting an expiration date</li><li>Changing their status to active or inactive</li></ul><h2 id="example-bot-usage" tabindex="-1">Example Bot Usage <a class="header-anchor" href="#example-bot-usage" aria-label="Permalink to “Example Bot Usage”">​</a></h2><p>Here is an example script to retrieve the entire project <strong>MyProduction</strong> using a bot:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> gazu</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gazu.set_host(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;yourkitsu.cg-wire.com/api/&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gazu.set_token(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;my_jwt_token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p = gazu.project.get_project_by_name(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;MyProduction&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>This script demonstrates how to use a bot to interact with the Kitsu API without using a real user&#39;s login credentials. Depending on your needs, if you have a bot that publishes comments, you can think about permission and give it the same rights as a physical user.</p><h2 id="security-considerations" tabindex="-1">Security Considerations <a class="header-anchor" href="#security-considerations" aria-label="Permalink to “Security Considerations”">​</a></h2><p>If your bot&#39;s token is compromised, you can regenerate a new token, which will revoke the old one, ensuring your system remains secure.</p>`,21)])])}const E=s(h,[["render",c]]);export{y as __pageData,E as default};
